curl -X POST "$AGENT_URL/execute" \
  -H "Content-Type: application/json" \
  -d '{"input": "say Testing $100 and 100% success"}' \
  -w "\n\nHTTP Status: %{http_code}\n"

echo ""

# Test 3: Check agent status
echo "=== Agent Health Check ==="
curl -X GET "$AGENT_URL/health" \
  -w "\n\nHTTP Status: %{http_code}\n"

echo ""

# Test 4: List available skills
echo "=== Available Skills ==="
curl -X GET "$AGENT_URL/skills" \
  -w "\n\nHTTP Status: %{http_code}\n"
```

### Example 5

```python
// echo/handler.test.js - Unit tests for the echo handler
// Demonstrates testing patterns for terminal agent skills

const assert = require('assert');
const echoHandler = require('./handler');

// Helper function to create mock context
function createMockContext(input, params = {}) {
    return {
        input: input,
        params: params,
        session: {},
        env: process.env
    };
}

// Test 1: Basic echo functionality
console.log('Running Test 1: Basic echo...');
try {
    const context = createMockContext('echo Hello', { message: 'Hello' });
    const result = echoHandler.handler(context);

    assert.strictEqual(result.success, true, 'Should return success');
    assert.strictEqual(result.output.echoed, 'Hello', 'Should echo the message');
    assert.strictEqual(result.output.echoCount, 1, 'Should increment echo count');
    console.log('✓ Test 1 passed');
} catch (err) {
    console.error('✗ Test 1 failed:', err.message);
}

// Test 2: Session state persistence
console.log('Running Test 2: Session state...');
try {
    const context1 = createMockContext('echo First', { message: 'First' });
    const result1 = echoHandler.handler(context1);

    const context2 = createMockContext('echo Second', { message: 'Second' });
    context2.session = result1.session; // Pass session from first call
    const result2 = echoHandler.handler(context2);

    assert.strictEqual(result1.output.echoCount, 1, 'First call count should be 1');
    assert.strictEqual(result2.output.echoCount, 2, 'Second call count should be 2');
    console.log('✓ Test 2 passed');
} catch (err) {
    console.error('✗ Test 2 failed:', err.message);
}

// Test 3: Timestamp is included
console.log('Running Test 3: Timestamp...');
try {
    const context = createMockContext('echo Test', { message: 'Test' });
    const result = echoHandler.handler(context);

    const timestamp = new Date(result.output.timestamp);
    const now = new Date();
    const diff = Math.abs(now - timestamp);

    assert(diff < 5000, 'Timestamp should be within 5 seconds of now');
    console.log('✓ Test 3 passed');
} catch (err) {
    console.error('✗ Test 3 failed:', err.message);
}

console.log('\n=== All tests completed ===');
```



## Common Mistakes

- Forgetting to escape special characters in regex trigger patterns, causing unexpected matching behavior or runtime errors
- Not handling missing or null parameters in the handler, leading to TypeError crashes when users omit required arguments
- Running the agent server without proper permission scoping, exposing unintended file system or system access
- Ignoring the session state object entirely, which means losing conversational context across multiple interactions
- Testing only with perfect inputs and never verifying error handling for malformed requests
- Hardcoding port numbers or file paths instead of using environment variables or configuration files
- Not implementing proper logging, making debugging production issues extremely difficult
- Creating skills with duplicate names or conflicting trigger patterns that cause routing ambiguity
- Forgetting to increment version numbers when deploying updates, leading to caching issues in clients
- Assuming synchronous execution when the handler is actually async, causing response delays or timeouts


## Best Practices

- Always validate and sanitize all input parameters before using them in file operations, system commands, or external API calls to prevent injection vulnerabilities
- Implement comprehensive logging at each stage (request received, skill matched, action executed, response sent) using structured logging formats like JSON for easier parsing and analysis
- Design skills with single responsibilities—each skill should do one thing well rather than trying to handle multiple unrelated use cases
- Use semantic versioning for skill manifests and maintain a changelog to track what changed between versions
- Write handler code defensively by checking for optional parameters and providing sensible defaults rather than crashing on missing data
- Store sensitive configuration (API keys, credentials) in environment variables and never commit them to version control
- Create a comprehensive test suite that covers happy paths, edge cases, and error conditions before deploying skills to production
- Document skill manifests thoroughly with descriptions and examples so other team members understand when and how to use each skill
- Monitor agent performance metrics (response time, error rate, skill usage distribution) to identify optimization opportunities
- Implement graceful degradation—your agent should provide helpful error messages instead of cryptic stack traces when things go wrong

