        success: true,
        output: {
            echoed: message,
            echoCount: echoCount,
            timestamp: timestamp
        },
        message: `"${message}"`,
        session: session
    };
}

// Export the handler for OpenCode to discover
module.exports = {
    handler: echoHandler,
    // Optional metadata for documentation
    description: 'Echoes a message back to the user',
    examples: [
        'echo Hello World',
        'say This will be echoed back'
    ]
};

